from bs4 import BeautifulSoup
import re

def detect_headings(html_content):
    """智能识别多级标题结构"""
    soup = BeautifulSoup(html_content, 'html.parser')

    # 微信公众号常见标题模式
    heading_patterns = [
        {  # 一级标题（通常带序号）
            'pattern': r'^(一、|第\d+章|【.*】)',
            'tag': 'h2',
            'class': 'level1'
        },
        {  # 二级标题（加粗+下划线）
            'selector': 'strong u, span[style*="underline"]',
            'tag': 'h3',
            'class': 'level2'
        },
        {  # 三级标题（特殊颜色）
            'selector': 'span[style*="#3da8f5"], span[style*="color: rgb(61, 168, 245)"]',
            'tag': 'h4',
            'class': 'level3'
        }
    ]

    # 自动识别并标记标题层级
    for elem in soup.find_all(string=re.compile(r'.{10,}')):
        parent = elem.parent

        # 跳过已处理的元素
        if parent.name in ['h2', 'h3', 'h4']:
            continue

        # 匹配一级标题模式
        text = elem.string.strip()
        for pattern in heading_patterns:
            if 'pattern' in pattern and re.match(pattern['pattern'], text):
                new_tag = soup.new_tag(pattern['tag'])
                new_tag['class'] = pattern['class']
                new_tag.string = text
                parent.replace_with(new_tag)
                break

        # 匹配样式选择器
        for pattern in heading_patterns:
            if 'selector' in pattern and parent.name != 'span':
                if parent.select(pattern['selector']):
                    new_tag = soup.new_tag(pattern['tag'])
                    new_tag['class'] = pattern['class']
                    new_tag.string = text
                    parent.replace_with(new_tag)
                    break

    return str(soup)

def improved_pdf_generator(article_url):
