        f"<div>{result['content']}</div>"
    )

    # 创建带层级样式的CSS
    css = CSS(string='''
        .level1 {
            font-size: 18pt;
            font-weight: 900;
            color: #2d2d2d;
            margin: 1.5em 0 0.5em;
            border-bottom: 2px solid #3da8f5;
            padding-bottom: 0.3em;
        }

        .level2 {
