def add_toc(html_content):
    """自动生成目录"""
    soup = BeautifulSoup(html_content, 'html.parser')
    toc = soup.new_tag('div', id='toc')
    toc.append(soup.new_tag('h2', string='目录'))

    ol = soup.new_tag('ol')
    for heading in soup.find_all(['h2', 'h3']):
        li = soup.new_tag('li')
        a = soup.new_tag('a', href=f"#{heading['id']}")
        a.string = heading.string
        li.append(a)
        ol.append(li)

    toc.append(ol)
    soup.body.insert(0, toc)
    return str(soup)
```

